+
+    #[test]
+    fn minimap_corner_all_variants_distinct() {
+        let corners = [
+            MinimapCorner::TopLeft,
+            MinimapCorner::TopRight,
+            MinimapCorner::BottomLeft,
+            MinimapCorner::BottomRight,
+        ];
+        for (i, a) in corners.iter().enumerate() {
+            for (j, b) in corners.iter().enumerate() {
+                if i == j {
+                    assert_eq!(a, b);
+                } else {
+                    assert_ne!(a, b);
+                }
+            }
+        }
+    }
